sql:
SELECT SUM(unemployed) AS total_unemployed
FROM labor_statistics
WHERE state_id = 1 AND year = 2023;

external_knowledge:
- "Overall picture of employment and training" refers to a comprehensive set of statistics that describe the state of employment and training programs in each region; 
- A "region" is a geographical area that may include multiple states or counties, and is used here as the primary unit of analysis;
- "Success rate" is a measure of how effective a program is in achieving its goals, often expressed as a percentage.

sql:
SELECT state_id, COUNT(program_id) AS num_programs
FROM unemployment_programs
GROUP BY state_id;

SELECT region_name
FROM regions
WHERE median_income = (
  SELECT MAX(median_income)
  FROM regions
);

SELECT SUM(displaced_workers) AS total_displaced_workers
FROM labor_statistics
WHERE state_id = (SELECT state_id FROM states WHERE state_name = 'Alaska');

SELECT agency_name, number_of_staff, number_of_clients_served
FROM employment_agencies
WHERE agency_id = 1;

SELECT 
  (SELECT COUNT(program_id) FROM unemployment_programs) AS total_programs,
  (SELECT COUNT(agency_id) FROM employment_agencies T1 JOIN states T2 ON T1.state_id = T2.state_id WHERE T2.state_name = 'Alaska') AS total_agencies;

SELECT AVG(displaced_workers) AS avg_displaced_workers, employment_rate
FROM labor_statistics
WHERE year = 2023 AND month = 'May';

SELECT number_of_beneficiaries AS beneficiaries_count
FROM unemployment_programs
WHERE program_id = 0 AND state_id = 1;
